class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False
        self.weight = 0

def autocomplete(root, prefix):
    node = root
    for ch in prefix:
        if ch not in node.children:
            return []
        node = node.children[ch]
    results = []
    _collect(node, prefix, results)
    return sorted(results, key=lambda x: -x[1])[:10]

def _collect(node, path, results):
    if node.is_end:
        results.append((path, node.weight))
    for ch, child in node.children.items():
        _collect(child, path + ch, results)
